function lensDisabledReasonForCommand(
  commandId: string,
  lensMode: CapabilityLensMode,
): string | undefined {
  if (lensMode !== 'structure' && lensMode !== 'mep') return undefined;
  const lensRules = LENS_DISABLED_COMMANDS[lensMode];
